import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"粥上的一点土","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/粥上的一点土.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/粥上的一点土.md"}'),o={name:"4.资源分区/7.物品与装备/9.消耗品/0.无支线/粥上的一点土.md"};function d(_,a,l,i,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"粥上的一点土",tabindex:"-1"},[p("粥上的一点土 "),e("a",{class:"header-anchor",href:"#粥上的一点土","aria-label":'Permalink to "粥上的一点土"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),s('<h1 id="粥上的一点土-1" tabindex="-1">粥上的一点土 <a class="header-anchor" href="#粥上的一点土-1" aria-label="Permalink to &quot;粥上的一点土&quot;">​</a></h1><p>粥上的一点土</p><p>500<br> 魔幻本质</p><p>乾隆年间，某地发生饥荒，当地知县请乾隆开粮仓赈灾，乾隆便派了当时掌管户部的宠臣和珅处理此事。<br> 接了钦差令的和珅依圣旨办事，却执意让手下在赈灾的粥里加一把土，你道这是为何？原来那救济粮根本放不到灾民的手里，总有人靠各种手段骗取救济粮，和珅自忖此事不得以武力压制，故出此谋。<br> 之后，骗取救济粮的人发现粥里有沙子，遂唾之，救济粮这才真正发到灾民的手中。</p><p>这是一袋外表普普通通的黄土，重量约10KG，可以使用1次。<br> 使用者可以以一个自由动作将黄土取出一把洒在任意一个物品上，则对方便不能看透该物品的本质。<br> 若该物品为目标非常想要的物品，则此时这把土会给该物品带来幻象，被认作是另一件东西，这是一个C级幻象来源的伪装效果。对此物品进行识破为目的的调查检定DC为12.<br> 该效果持续一个场景。</p><p>“人不患寡，患不公。”<br> 相传和珅此举还另有深意，粥中掺土是为灾民能知晓，朝廷已尽全力，此粥便是官府能拿出最好的救灾之物。<br> 如此，灾民方可老老实实地接受这掺了土的粥而不要求更多。<br> 此是为官之道，亦是和珅处事之道。</p><p>使用者若将黄土洒在自己的饮食中吃下，目睹了这一行为的NPC会认为使用者在某件事（与使用者正在做的行为有关）上尽心尽力，鞠躬尽瘁。</p><p>若NPC对使用者抱有怀疑，则该效果视为一个C级思维控制来源的效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
